redis_client = redis.StrictRedis(host=REDIS_HOST, port=REDIS_PORT, db=REDIS_DB, decode_responses=True)

# --- Redis Session Management ---
# For simplicity, we're replacing Flask's default session management
# with a custom one that uses Redis SET/GET directly on the 'session' object.
# In a real-world high-traffic app, you might use a more robust Flask Session
# extension like Flask-Session or implement a custom SessionInterface.

@app.before_request
def load_session():
    session_id = request.cookies.get('session_id')
    if session_id:
        session_data_json = redis_client.get(f'session:{session_id}')
        if session_data_json:
            session.update(json.loads(session_data_json))
        else:
            # Session ID found but data expired or not found in Redis
            # Clear invalid session ID from cookie
            response = make_response('')
            response.set_cookie('session_id', '', expires=0)
            return response # To avoid processing with an invalid session state
    # If no session_id in cookie, session object remains empty, a new one will be created on save

@app.after_request
def save_session(response):
    if session.modified:
        session_id = request.cookies.get('session_id')
        if not session_id:
            # Generate a new session ID if it doesn't exist
            session_id = str(time.time_ns()) # A simple unique ID, use UUID in production
            response.set_cookie('session_id', session_id,
                                httponly=True,
                                secure=False, # Set to True in production with HTTPS
                                max_age=SESSION_EXPIRATION_SECONDS,
                                expires=time.time() + SESSION_EXPIRATION_SECONDS)

        # Store session data in Redis
        redis_client.setex(f'session:{session_id}',
                           SESSION_EXPIRATION_SECONDS,
                           json.dumps(dict(session)))
    return response

# --- Redis Caching Decorator ---

def cache(key_prefix, ex=CACHE_EXPIRATION_SECONDS):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            # Generate a cache key based on function name, args, and kwargs
            # For complex args/kwargs, you might need a more sophisticated serialization
            # This example assumes args/kwargs are simple and can be stringified
            cache_key_parts = [key_prefix, func.__name__]
            cache_key_parts.extend(map(str, args))
            cache_key_parts.extend(f"{k}={v}" for k, v in sorted(kwargs.items()))
            cache_key = ":".join(cache_key_parts)

            # Try to get data from cache
            cached_data = redis_client.get(cache_key)
            if cached_data:
                print(f"Cache hit for key: {cache_key}")
                return json.loads(cached_data)

            print(f"Cache miss for key: {cache_key}. Executing function...")
            # If not in cache, execute the original function
            result = func(*args, **kwargs)

            # Store the result in cache
            redis_client.setex(cache_key, ex, json.dumps(result))
            return result
        return wrapper
    return decorator

