@app.route('/')
def index():
    user = session.get('username')
    if user:
        return f'Hello, {user}! <a href="/logout">Logout</a> | <a href="/profile">Profile</a>'
    return 'You are not logged in. <a href="/login">Login</a>'

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form['username']
        password = request.form['password'] # In real app, validate credentials
        if username and password:
            session['username'] = username
            session['logged_in'] = True
            return redirect(url_for('index'))
    return '''
        <form method="post">
            <p><input type=text name=username placeholder="Username">
            <p><input type=password name=password placeholder="Password">
            <p><input type=submit value=Login>
        </form>
    '''

@app.route('/logout')
def logout():
    session_id = request.cookies.get('session_id')
    if session_id:
        redis_client.delete(f'session:{session_id}') # Invalidate session in Redis
    session.clear() # Clear Flask's session object
    response = make_response(redirect(url_for('index')))
    response.set_cookie('session_id', '', expires=0) # Clear session cookie
    return response

@app.route('/profile')
def profile():
    if not session.get('logged_in'):
        return redirect(url_for('login'))

    username = session['username']
    # Example of using the caching decorator for expensive data
    user_data = get_expensive_data(username) # This will be cached

    return f'''
        <h1>User Profile: {username}</h1>
        <p>This data is fetched using an expensive operation, potentially from cache.</p>
        <pre>{json.dumps(user_data, indent=2)}</pre>
        <p><a href="/">Back to Home</a></p>
    '''

@app.route('/clear_cache/<key_prefix>')
def clear_cache(key_prefix):
    """Endpoint to manually clear cache entries for a given prefix."""
    if not session.get('logged_in'):
        return redirect(url_for('login'))

    count = 0
    for key in redis_client.scan_iter(f"{key_prefix}:*"):
        redis_client.delete(key)
        count += 1
    return f"Cleared {count} cache entries with prefix '{key_prefix}'."

